import re

def detect_pii_regex(message: str) -> list:
    patterns = {
        'email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        'phone': r'\b(?:\+?1[-.\s]?)?(?:\(?[0-9]{3}\)?[-.\s]?)?[0-9]{3}[-.\s]?[0-9]{4}\b',
        'ssn': r'\b\d{3}-?\d{2}-?\d{4}\b',
        'api_key': r'\b(?:sk-|ak-)[A-Za-z0-9]{32,}\b'
    }
    findings = []
    for pii_type, pattern in patterns.items():
        matches = re.finditer(pattern, message)
        for match in matches:
            findings.append({
                'type': pii_type,
                'value': match.group(),
                'start': match.start(),
                'end': match.end()
           ])
    return findings

from ag2 import GroupChat, Agent

def pii_message_hook(message):
    if detect_pii_regex(message.content):
        print(f'🚨 PII detected in {message.sender}: {message.content[:100]}...')
        return {'block': True, 'reason': 'PII detected'}
    return {'block': False}

# Register hook
groupchat = GroupChat(agents=[agent1, agent2], message_hook=pii_message_hook)

def audit_conversation_pii(history: list):
    total_pii = 0
    pii_by_agent = {}
    for msg in history:
        findings = detect_pii_regex(msg['content'])
        total_pii += len(findings)
        agent_name = msg.get('sender', 'unknown')
        pii_by_agent[agent_name] = pii_by_agent.get(agent_name, 0) + len(findings)
    return {
        'total_pii_instances': total_pii,
        'pii_by_agent': pii_by_agent,
        'risk_score': total_pii / len(history) if history else 0
    }

