import re

def redact_pii_filter(message: str) -> str:
    patterns = {
        'EMAIL': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        'PHONE': r'\b(?:\+?1[-.\s]?)?(?:\(?[0-9]{3}\)?[-.\s]?)?[0-9]{3}[-.\s]?[0-9]{4}\b',
        'SSN': r'\b\d{3}-?\d{2}-?\d{4}\b'
    }
    redacted = message
    for pii_type, pattern in patterns.items():
        redacted = re.sub(pattern, f'[{pii_type}_REDACTED]', redacted)
    return redacted

def ag2_pii_hook(message):
    message.content = redact_pii_filter(message.content)
    return message

from ag2 import GroupChatManager

class SafeSpeakerSelector(GroupChatManager):
    def select_speaker(self, last_speaker, selector):
        # Get candidate context
        context = self.get_conversation_context()
        # Filter PII from context
        safe_context = redact_pii_filter(str(context))
        # Use safe context for selection
        selector.context = safe_context
        return super().select_speaker(last_speaker, selector)

from ag2 import CodeExecutorAgent

class SafeCodeAgent(CodeExecutorAgent):
    def execute_code(self, code: str):
        # Scrub PII from code before execution
        safe_code = redact_pii_filter(code)
        if safe_code != code:
            print('⚠️ PII removed from code before execution')
        return super().execute_code(safe_code)

# Usage
safe_coder = SafeCodeAgent(name='safe-coder', code_sandbox=True)
